      <nav className="space-x-4">
        <a href="#" className="text-gray-700 hover:text-blue-500">Home</a>
        <a href="#" className="text-gray-700 hover:text-blue-500">About</a>
        <a href="#" className="text-gray-700 hover:text-blue-500">Contact</a>
      </nav>
    </header>
  );
}
